create policy "admin reads submissions" on public.assignment_submissions for select using ((EXISTS ( SELECT 1
   FROM profiles
  WHERE ((profiles.id = auth.uid()) AND (profiles.role = 'admin'::text)))));
create policy "student reads own submissions" on public.assignment_submissions for select using ((assignment_id IN ( SELECT assignments.id
   FROM assignments
  WHERE (assignments.student_id IN ( SELECT students.id
           FROM students
          WHERE (students.profile_id = auth.uid()))))));
create policy "teacher reads own submissions" on public.assignment_submissions for select using ((assignment_id IN ( SELECT assignments.id
   FROM assignments
  WHERE (assignments.teacher_id IN ( SELECT teachers.id
           FROM teachers
          WHERE (teachers.profile_id = auth.uid()))))));
create policy "admin reads assignments" on public.assignments for select using ((EXISTS ( SELECT 1
   FROM profiles
  WHERE ((profiles.id = auth.uid()) AND (profiles.role = 'admin'::text)))));
create policy "student reads own assignments" on public.assignments for select using ((student_id IN ( SELECT students.id
   FROM students
  WHERE (students.profile_id = auth.uid()))));
create policy "teacher reads own assignments" on public.assignments for select using ((teacher_id IN ( SELECT teachers.id
   FROM teachers
  WHERE (teachers.profile_id = auth.uid()))));
create policy "Availability slots are publicly visible" on public.availability_slots for select using ((is_active = true));
create policy "Teachers manage own availability" on public.availability_slots for all using ((auth.uid() = ( SELECT teachers.profile_id
   FROM teachers
  WHERE (teachers.id = availability_slots.teacher_id))));
create policy "Students can create bookings" on public.bookings for insert to authenticated with check ((student_id = auth_student_id()));
create policy "Students see own bookings" on public.bookings for select to authenticated using ((student_id = auth_student_id()));
create policy "Teachers can update booking status" on public.bookings for update using ((auth.uid() = ( SELECT teachers.profile_id
   FROM teachers
  WHERE (teachers.id = bookings.teacher_id))));
create policy "Teachers see own bookings" on public.bookings for select using ((auth.uid() = ( SELECT teachers.profile_id
   FROM teachers
  WHERE (teachers.id = bookings.teacher_id))));
create policy "Students see own payments" on public.payments for select using ((auth.uid() = ( SELECT students.profile_id
   FROM students
  WHERE (students.id = payments.student_id))));
create policy "Teachers see own payments" on public.payments for select using ((auth.uid() = ( SELECT teachers.profile_id
   FROM teachers
  WHERE (teachers.id = payments.teacher_id))));
create policy "Plans are publicly visible" on public.plans for select using ((is_active = true));
create policy "Students can read teacher profiles" on public.profiles for select using ((EXISTS ( SELECT 1
   FROM ((teachers t
     JOIN bookings b ON ((b.teacher_id = t.id)))
     JOIN students s ON ((s.id = b.student_id)))
  WHERE ((t.profile_id = profiles.id) AND (s.profile_id = auth.uid())))));
create policy "Users can update own profile" on public.profiles for update using ((auth.uid() = id));
create policy "Users can view own profile" on public.profiles for select using ((auth.uid() = id));
create policy "Session participants can view" on public.sessions for select using ((auth.uid() IN ( SELECT p.profile_id
   FROM (students p
     JOIN bookings b ON ((b.student_id = p.id)))
  WHERE (b.id = sessions.booking_id)
UNION
 SELECT t.profile_id
   FROM (teachers t
     JOIN bookings b ON ((b.teacher_id = t.id)))
  WHERE (b.id = sessions.booking_id))));
create policy "Students can read own sessions" on public.sessions for select using ((EXISTS ( SELECT 1
   FROM (bookings b
     JOIN students s ON ((s.id = b.student_id)))
  WHERE ((b.id = sessions.booking_id) AND (s.profile_id = auth.uid())))));
create policy "Teachers can insert sessions" on public.sessions for insert with check ((EXISTS ( SELECT 1
   FROM (bookings b
     JOIN teachers t ON ((t.id = b.teacher_id)))
  WHERE ((b.id = sessions.booking_id) AND (t.profile_id = auth.uid())))));
create policy "Teachers can update sessions" on public.sessions for update using ((EXISTS ( SELECT 1
   FROM (bookings b
     JOIN teachers t ON ((t.id = b.teacher_id)))
  WHERE ((b.id = sessions.booking_id) AND (t.profile_id = auth.uid())))));
create policy "Students can insert own record" on public.students for insert to authenticated with check ((auth.uid() = profile_id));
create policy "Students can update own record" on public.students for update using ((auth.uid() = profile_id));
create policy "Students can view own record" on public.students for select using ((auth.uid() = profile_id));
create policy "Teachers can read student intake" on public.students for select using ((auth.uid() IN ( SELECT t.profile_id
   FROM (teachers t
     JOIN bookings b ON ((b.teacher_id = t.id)))
  WHERE (b.student_id = students.id))));
create policy "Students can view own subscriptions" on public.subscriptions for select using ((auth.uid() = ( SELECT students.profile_id
